import torch
from flask import Flask, request, jsonify
from transformers import AutoTokenizer, AutoModelForSequenceClassification

MODEL_DIR = "/app/model_cache/sentiment_model"

app = Flask(__name__)

tokenizer = AutoTokenizer.from_pretrained(MODEL_DIR)
model = AutoModelForSequenceClassification.from_pretrained(MODEL_DIR)
model.eval()

id2label = {int(k): v for k, v in model.config.id2label.items()}


@app.route("/sentiment", methods=["POST"])
def sentiment():
    data = request.get_json(silent=True)
    if not data or "text" not in data or not isinstance(data["text"], str):
        return jsonify({"error": "Request must include JSON with a 'text' string field."}), 400

    text = data["text"]
    inputs = tokenizer(text, return_tensors="pt", truncation=True, padding=True)
    with torch.no_grad():
        logits = model(**inputs).logits
    probs = torch.softmax(logits, dim=-1)[0]

    conf = {}
    for idx, label in id2label.items():
        conf[label.lower()] = float(probs[idx])

    sentiment_label = id2label[int(torch.argmax(probs))].lower()
    return jsonify({
        "sentiment": sentiment_label,
        "confidence": {
            "positive": conf.get("positive", 0.0),
            "negative": conf.get("negative", 0.0),
        },
    })


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)
